// Message handler registry
class MessageHandlerRegistry extends EventEmitter {
  constructor() {
    super();
    this.handlers = new Map();
  }

  register(messageType, handler) {
    if (!ALLOWED_MESSAGE_TYPES.includes(messageType)) {
      throw new Error(`Cannot register handler for unknown message type: ${messageType}`);
    }
    this.handlers.set(messageType, handler);
    logger.info(`Registered handler for message type: ${messageType}`);
  }

  async handle(messageType, payload, metadata) {
    const handler = this.handlers.get(messageType);
    if (!handler) {
      throw new Error(`No handler registered for message type: ${messageType}`);
    }
    return handler(payload, metadata);
  }

  hasHandler(messageType) {
    return this.handlers.has(messageType);
  }
}

