// Database query builder using parameterized queries only
class SafeQueryBuilder {
  static insert(table, data) {
    validateTableName(table);
    const columns = Object.keys(data);
    validateColumns(table, columns);

    const values = Object.values(data).map(v =>
      typeof v === 'object' && v !== null ? JSON.stringify(v) : v
    );
    const placeholders = columns.map((_, i) => `$${i + 1}`);

    // Use identifier quoting for table/column names (already validated against whitelist)
    const query = `INSERT INTO "${table}" (${columns.map(c => `"${c}"`).join(', ')}) VALUES (${placeholders.join(', ')}) RETURNING *`;

    return { query, values };
  }

  static update(table, data, conditions) {
    validateTableName(table);
    const dataColumns = Object.keys(data);
    const condColumns = Object.keys(conditions);
    validateColumns(table, [...dataColumns, ...condColumns]);

    const allValues = [];
    let paramIndex = 1;

    const setClauses = dataColumns.map((col) => {
      const val = typeof data[col] === 'object' && data[col] !== null ? JSON.stringify(data[col]) : data[col];
      allValues.push(val);
      return `"${col}" = $${paramIndex++}`;
    });

    const whereClauses = condColumns.map((col) => {
      allValues.push(conditions[col]);
      return `"${col}" = $${paramIndex++}`;
    });

    const query = `UPDATE "${table}" SET ${setClauses.join(', ')} WHERE ${whereClauses.join(' AND ')} RETURNING *`;

    return { query, values: allValues };
  }

  static delete(table, conditions) {
    validateTableName(table);
    const condColumns = Object.keys(conditions);
    validateColumns(table, condColumns);

    const values = [];
    let paramIndex = 1;

    const whereClauses = condColumns.map((col) => {
      values.push(conditions[col]);
      return `"${col}" = $${paramIndex++}`;
    });

    const query = `DELETE FROM "${table}" WHERE ${whereClauses.join(' AND ')} RETURNING *`;

    return { query, values };
  }

  static select(table, conditions, columns = ['*']) {
    validateTableName(table);
    const condColumns = Object.keys(conditions);
    if (condColumns.length > 0) {
      validateColumns(table, condColumns);
    }
    if (columns[0] !== '*') {
      validateColumns(table, columns);
    }

    const values = [];
    let paramIndex = 1;

    const selectCols = columns[0] === '*' ? '*' : columns.map(c => `"${c}"`).join(', ');

    const whereClauses = condColumns.map((col) => {
      values.push(conditions[col]);
      return `"${col}" = $${paramIndex++}`;
    });

    let query = `SELECT ${selectCols} FROM "${table}"`;
    if (whereClauses.length > 0) {
      query += ` WHERE ${whereClauses.join(' AND ')}`;
    }

    return { query, values };
  }
}

// Execute database query with retries
async function executeQuery(queryObj, retries = config.retries.maxRetries) {
  let lastError;
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      const result = await pool.query(queryObj.query, queryObj.values);
      return result;
    } catch (error) {
      lastError = error;
      logger.warn(`Database query attempt ${attempt}/${retries} failed`, {
        error: error.message,
        query: queryObj.query,
      });
      if (attempt < retries) {
        await new Promise(resolve => setTimeout(resolve, config.retries.retryDelay * attempt));
      }
    }
  }
  throw lastError;
}

// Execute database transaction
async function executeTransaction(queries) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const results = [];
    for (const queryObj of queries) {
      const result = await client.query(queryObj.query, queryObj.values);
      results.push(result);
    }
    await client.query('COMMIT');
    return results;
  } catch (error) {
    await client.query('ROLLBACK');
    throw error;
  } finally {
    client.release();
  }
}

