// Message processor
async function processMessage(msg, channel) {
  const startTime = Date.now();
  let messageContent;
  let messageType;

  try {
    // Parse message content
    const rawContent = msg.content.toString();
    messageContent = JSON.parse(rawContent);

    // Extract message type and validate
    messageType = messageContent.type;
    if (!messageType || typeof messageType !== 'string') {
      throw new Error('Message must contain a valid "type" field');
    }

    if (!ALLOWED_MESSAGE_TYPES.includes(messageType)) {
      throw new Error(`Unknown message type: ${messageType}. Allowed types: ${ALLOWED_MESSAGE_TYPES.join(', ')}`);
    }

    if (!registry.hasHandler(messageType)) {
      throw new Error(`No handler registered for message type: ${messageType}`);
    }

    const payload = messageContent.payload || {};
    const metadata = {
      messageId: msg.properties.messageId || uuidv4(),
      correlationId: msg.properties.correlationId || uuidv4(),
      timestamp: msg.properties.timestamp || Date.now(),
      actorId: messageContent.actorId || msg.properties.userId || 'system',
      headers: msg.properties.headers || {},
      retryCount: (msg.properties.headers && msg.properties.headers['x-retry-count']) || 0,
    };

    logger.info('Processing message', {
      messageType,
      messageId: metadata.messageId,
      correlationId: metadata.correlationId,
    });

    // Execute handler
    const result = await registry.handle(messageType, payload, metadata);

    const duration = Date.now() - startTime;
    logger.info('Message processed successfully', {
      messageType,
      messageId: metadata.messageId,
      duration: `${duration}ms`,
    });

    // Acknowledge message
    channel.ack(msg);
    return result;

  } catch (error) {
    const duration = Date.now() - startTime;
    const retryCount = (msg.properties.headers && msg.properties.headers['x-retry-count']) || 0;

    logger.error('Error processing message', {
      messageType: messageType || 'unknown',
      error: error.message,
      stack: error.stack,
      duration: `${duration}ms`,
      retryCount,
    });

    if (retryCount < config.retries.maxRetries) {
      // Republish with incremented retry count
      try {
        const headers = { ...msg.properties.headers, 'x-retry-count': retryCount + 1 };
        channel.publish('', config.rabbitmq.queue, msg.content, {
          ...msg.properties,
          headers,
        });
        logger.info('Message requeued for retry', {
          messageType: messageType || 'unknown',
          retryCount: retryCount + 1,
        });
      } catch (publishError) {
        logger.error('Failed to requeue message', { error: publishError.message });
      }
      channel.ack(msg);
    } else {
      // Send to dead letter queue
      try {
        const dlqPayload = {
          originalMessage: messageContent,
          error: error.message,
          stack: error.stack,
          retryCount,
          failedAt: new Date().toISOString(),
        };
        channel.publish('', config.rabbitmq.deadLetterQueue, Buffer.from(JSON.stringify(dlqPayload)), {
          persistent: true,
          messageId: msg.properties.messageId,
          correlationId: msg.properties.correlationId,
        });
        logger.warn('Message sent to dead letter queue', {
          messageType: messageType || 'unknown',
          retryCount,
        });
      } catch (dlqError) {
        logger.error('Failed to send message to DLQ', { error: dlqError.message });
      }
      channel.ack(msg);
    }
  }
}

// RabbitMQ connection and consumer setup
class MessageConsumer {
  constructor() {
    this.connection = null;
    this.channel = null;
    this.isShuttingDown = false;
    this.reconnectTimer = null;
  }

  async connect() {
    try {
      logger.info('Connecting to RabbitMQ...', { url: config.rabbitmq.url.replace(/\/\/.*@/, '//***@') });

      this.connection = await amqp.connect(config.rabbitmq.url);

      this.connection.on('error', (err) => {
        logger.error('RabbitMQ connection error', { error: err.message });
      });

      this.connection.on('close', () => {
        if (!this.isShuttingDown) {
          logger.warn('RabbitMQ connection closed, attempting reconnect...');
          this.scheduleReconnect();
        }
      });

      this.channel = await this.connection.createChannel();

      this.channel.on('error', (err) => {
        logger.error('RabbitMQ channel error', { error: err.message });
      });

      this.channel.on('close', () => {
        if (!this.isShuttingDown) {
          logger.warn('RabbitMQ channel closed');
        }
      });

      // Set prefetch
      await this.channel.prefetch(config.rabbitmq.prefetch);

      // Assert queues
      await this.channel.assertQueue(config.rabbitmq.queue, {
        durable: true,
        arguments: {
          'x-dead-letter-exchange': '',
          'x-dead-letter-routing-key': config.rabbitmq.deadLetterQueue,
        },
      });

      await this.channel.assertQueue(config.rabbitmq.deadLetterQueue, {
        durable: true,
      });

      logger.info('RabbitMQ connected and queues asserted', {
        queue: config.rabbitmq.queue,
        dlq: config.rabbitmq.deadLetterQueue,
        prefetch: config.rabbitmq.prefetch,
      });

      // Start consuming
      await this.channel.consume(config.rabbitmq.queue, (msg) => {
        if (msg) {
          processMessage(msg, this.channel);
        }
      }, { noAck: false });

      logger.info('Consumer started, waiting for messages...');

    } catch (error) {
      logger.error('Failed to connect to RabbitMQ', { error: error.message });
      this.scheduleReconnect();
    }
  }

  scheduleReconnect() {
    if (this.isShuttingDown) return;

    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
    }

    this.reconnectTimer = setTimeout(async () => {
      logger.info('Attempting to reconnect to RabbitMQ...');
      await this.connect();
    }, config.rabbitmq.reconnectDelay);
  }

  async shutdown() {
    this.isShuttingDown = true;

    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
    }

    try {
      if (this.channel) {
        await this.channel.close();
        logger.info('RabbitMQ channel closed');
      }
      if (this.connection) {
        await this.connection.close();
        logger.info('RabbitMQ connection closed');
      }
    } catch (error) {
      logger.error('Error during RabbitMQ shutdown', { error: error.message });
    }
  }
}

// Health check HTTP server
const http = require('http');

function createHealthServer(consumer) {
  const server = http.createServer(async (req, res) => {
    if (req.url === '/health' && req.method === 'GET') {
      try {
        // Check database
        await pool.query('SELECT 1');

        // Check RabbitMQ
        const rabbitOk = consumer.connection && consumer.channel;

        if (rabbitOk) {
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({
            status: 'healthy',
            timestamp: new Date().toISOString(),
            services: {
              database: 'connected',
              rabbitmq: 'connected',
            },
          }));
        } else {
          res.writeHead(503, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({
            status: 'unhealthy',
            timestamp: new Date().toISOString(),
            services: {
              database: 'connected',
              rabbitmq: 'disconnected',
            },
          }));
        }
      } catch (error) {
        res.writeHead(503, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({
          status: 'unhealthy',
          timestamp: new Date().toISOString(),
          error: error.message,
        }));
      }
    } else if (req.url === '/ready' && req.method === 'GET') {
      const ready = consumer.connection && consumer.channel;
      res.writeHead(ready ? 200 : 503, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ready }));
    } else {
      res.writeHead(404);
      res.end('Not Found');
    }
  });

  const port = process.env.HEALTH_PORT || 3000;
  server.listen(port, () => {
    logger.info(`Health check server listening on port ${port}`);
  });

  return server;
}

// Main startup
async function main() {
  logger.info('Starting message processing microservice...');

  const consumer = new MessageConsumer();

  // Create health check server
  const healthServer = createHealthServer(consumer);

  // Connect to RabbitMQ
  await consumer.connect();

  // Graceful shutdown
  const shutdown = async (signal) => {
    logger.info(`Received ${signal}, initiating graceful shutdown...`);

    // Stop accepting new messages
    await consumer.shutdown();

    // Close health server
    healthServer.close(() => {
      logger.info('Health check server closed');
    });

    // Close database pool
    try {
      await pool.end();
      logger.info('Database pool closed');
    } catch (error) {
      logger.error('Error closing database pool', { error: error.message });
    }

    logger.info('Shutdown complete');
    process.exit(0);
  };

  process.on('SIGTERM', () => shutdown('SIGTERM'));
  process.on('SIGINT', () => shutdown('SIGINT'));

  process.on('uncaughtException', (error) => {
    logger.error('Uncaught exception', { error: error.message, stack: error.stack });
    shutdown('uncaughtException');
  });

  process.on('unhandledRejection', (reason, promise) => {
    logger.error('Unhandled rejection', { reason: String(reason) });
  });
}

main().catch((error) => {
  logger.error('Fatal error during startup', { error: error.message, stack: error.stack });
  process.exit(1);
});

module.exports = {
  registry,
  MessageHandlerRegistry,
  SafeQueryBuilder,
  processMessage,
  config,
  validateTableName,
  validateColumns,
  sanitizeString,
  validatePayload,
  ALLOWED_MESSAGE_TYPES,
  ALLOWED_TABLES,
  ALLOWED_COLUMNS,
};